import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    if not unvisited_customers:
        return None

    min_combined_metric = float('inf')
    best_node = None

    for i, customer in enumerate(unvisited_customers):
        distance = np.linalg.norm(cur_truck_pos - customer)
        remaining_customers = [c for j, c in enumerate(unvisited_customers) if j != i]
        potential_delay = 0

        for truck_pos in all_truck_pos:
            if np.array_equal(truck_pos, cur_truck_pos):
                continue
            closest_remaining = min(remaining_customers, key=lambda c: np.linalg.norm(truck_pos - c), default=None)
            if closest_remaining is not None:
                alternative_distance = np.linalg.norm(truck_pos - closest_remaining)
                if alternative_distance < distance:
                    potential_delay += distance - alternative_distance

        proximity_multiplier = 1 if len(unvisited_customers) > 1 else 0
        current_metric = distance + potential_delay + proximity_multiplier * len(unvisited_customers)

        if current_metric < min_combined_metric:
            min_combined_metric = current_metric
            best_node = i

    return best_node
